"""
UMBRELLA SEISMIC SENSING V1
============================
Real-time seismic monitoring dashboard - Team Project Umbrella
Connects to Behringer Flow 8 via USB, streams 3 geophone channels.
Features: WAV recording, Audacity-style timeline, time-vs-amplitude display.

Requirements:
    pip install flask flask-socketio sounddevice numpy

Usage:
    1. Connect Flow 8 to PC via USB (USB-MODE: RECORDING)
    2. Plug Geophone 1 -> Input 1, Geophone 2 -> Input 2, Geophone 3 -> Input 3
    3. Run:  python geophone_app.py
    4. Open: http://127.0.0.1:5000
"""

from flask import Flask, render_template_string, send_file
from flask_socketio import SocketIO
import numpy as np
import datetime
import threading
import wave
import io
import time as time_module

try:
    import sounddevice as sd
    SOUNDDEVICE_AVAILABLE = True
except (ImportError, OSError) as e:
    SOUNDDEVICE_AVAILABLE = False
    print(f"[WARN] sounddevice not available: {e}")
    print("[WARN] Running in DEMO mode with simulated data.\n")

app = Flask(__name__)
socketio = SocketIO(app, cors_allowed_origins="*", async_mode='threading')

SAMPLE_RATE = 48000
DOWNSAMPLE_FACTOR = 4
NUM_GEOPHONES = 3

stream = None
is_running = False
device_info_cache = None
demo_thread = None

is_recording = False
recording_lock = threading.Lock()
recorded_chunks = []
recording_start_time = None


def log_msg(message, level="info"):
    timestamp = datetime.datetime.now().strftime("%H:%M:%S.%f")[:-3]
    socketio.emit('sys_log', {'msg': f"[{timestamp}] {message}", 'level': level})


def find_flow8_device():
    if not SOUNDDEVICE_AVAILABLE:
        return None, None
    devices = sd.query_devices()
    candidates = []
    for i, dev in enumerate(devices):
        name = dev['name'].lower()
        if any(kw in name for kw in ['flow 8', 'flow8', 'behringer', 'usb audio codec']):
            if dev['max_input_channels'] >= NUM_GEOPHONES:
                candidates.append((i, dev))
    if candidates:
        candidates.sort(key=lambda x: x[1]['max_input_channels'], reverse=True)
        return candidates[0]
    for i, dev in enumerate(devices):
        name = dev['name'].lower()
        if 'usb' in name and dev['max_input_channels'] >= NUM_GEOPHONES:
            candidates.append((i, dev))
    if candidates:
        candidates.sort(key=lambda x: x[1]['max_input_channels'], reverse=True)
        return candidates[0]
    return None, None


def list_audio_devices():
    if not SOUNDDEVICE_AVAILABLE:
        return "sounddevice module not available"
    devices = sd.query_devices()
    lines = []
    for i, dev in enumerate(devices):
        if dev['max_input_channels'] > 0:
            lines.append(f"  [{i}] {dev['name']} -- {dev['max_input_channels']} in ch, SR: {dev['default_samplerate']}")
    return "\n".join(lines) if lines else "  No input devices found."


def audio_callback(indata, frames, time_info, status):
    global is_running, is_recording
    if not is_running:
        return
    if status:
        log_msg(f"Audio status: {status}", "warn")
    if is_recording:
        with recording_lock:
            chunk = np.zeros((indata.shape[0], NUM_GEOPHONES), dtype=np.float32)
            for i in range(NUM_GEOPHONES):
                col = min(i, indata.shape[1] - 1)
                chunk[:, i] = indata[:, col]
            recorded_chunks.append(chunk)
    data = {}
    for i in range(NUM_GEOPHONES):
        col = min(i, indata.shape[1] - 1)
        ch = indata[::DOWNSAMPLE_FACTOR, col].tolist()
        rms = float(np.sqrt(np.mean(indata[:, col] ** 2)))
        peak = float(np.max(np.abs(indata[:, col])))
        data[f'ch{i+1}'] = ch
        data[f'rms{i+1}'] = rms
        data[f'peak{i+1}'] = peak
    socketio.emit('audio_data', data)


def demo_data_generator():
    global is_recording
    t = 0.0
    configs = [
        (4.5, 0.15, 0.05, 0.0),
        (3.2, 0.12, 0.04, 0.8),
        (5.8, 0.10, 0.06, 1.5),
    ]
    while is_running:
        samples = 256
        dt = samples / SAMPLE_RATE
        t_arr = np.linspace(t, t + dt, samples)
        data = {}
        signals = []
        for i, (freq, amp, noise_amp, phase) in enumerate(configs):
            base = amp * np.sin(2 * np.pi * freq * t_arr + phase)
            noise = noise_amp * np.random.randn(samples)
            if np.random.random() < 0.018:
                sp = np.random.randint(0, samples)
                length = min(30, samples - sp)
                noise[sp:sp+length] += 0.4 * np.exp(-np.linspace(0, 3, length))
            signal = base + noise
            signals.append(signal.astype(np.float32))
            data[f'ch{i+1}'] = signal.tolist()[::DOWNSAMPLE_FACTOR]
            data[f'rms{i+1}'] = float(np.sqrt(np.mean(signal ** 2)))
            data[f'peak{i+1}'] = float(np.max(np.abs(signal)))
        if is_recording:
            with recording_lock:
                recorded_chunks.append(np.column_stack(signals))
        socketio.emit('audio_data', data)
        t += dt
        time_module.sleep(dt)


@socketio.on('connect')
def handle_connect():
    log_msg("Client connected to Umbrella Seismic Sensing.")

@socketio.on('scan_devices')
def handle_scan():
    log_msg("Scanning audio devices...")
    if not SOUNDDEVICE_AVAILABLE:
        log_msg("sounddevice not installed -- demo mode only.", "warn")
        socketio.emit('device_status', {'found': False, 'mode': 'demo', 'name': 'Demo Mode', 'channels': NUM_GEOPHONES})
        return
    dev_index, dev_info = find_flow8_device()
    device_list = list_audio_devices()
    log_msg(f"Available input devices:\n{device_list}")
    if dev_info:
        global device_info_cache
        device_info_cache = (dev_index, dev_info)
        name = dev_info['name']
        max_ch = dev_info['max_input_channels']
        log_msg(f"DETECTED: [{dev_index}] {name} ({max_ch} channels)", "success")
        socketio.emit('device_status', {'found': True, 'mode': 'live', 'name': name, 'device_index': dev_index, 'channels': max_ch})
    else:
        log_msg("No compatible USB audio device found.", "warn")
        socketio.emit('device_status', {'found': False, 'mode': 'demo', 'name': 'Demo Mode', 'channels': NUM_GEOPHONES})

@socketio.on('start')
def handle_start(data=None):
    global stream, is_running, demo_thread
    if is_running:
        log_msg("Already running.", "warn")
        return
    is_running = True
    if SOUNDDEVICE_AVAILABLE:
        dev_index, dev_info = device_info_cache if device_info_cache else (None, None)
        if dev_info is None:
            dev_index, dev_info = find_flow8_device()
        if dev_info:
            try:
                max_ch = dev_info['max_input_channels']
                sr = dev_info['default_samplerate']
                log_msg(f"Opening [{dev_index}] {max_ch}ch at {int(sr)}Hz...")
                stream = sd.InputStream(device=dev_index, samplerate=sr, channels=max_ch, blocksize=1024, callback=audio_callback)
                stream.start()
                log_msg("LIVE audio stream started.", "success")
                for g in range(NUM_GEOPHONES):
                    log_msg(f"  Geophone {g+1} -> Input {g+1}")
                socketio.emit('stream_state', {'running': True, 'mode': 'live'})
                return
            except Exception as e:
                log_msg(f"Hardware error: {e}", "error")
                is_running = False
    is_running = True
    log_msg("DEMO mode -- synthetic seismic data.", "warn")
    demo_thread = threading.Thread(target=demo_data_generator, daemon=True)
    demo_thread.start()
    socketio.emit('stream_state', {'running': True, 'mode': 'demo'})

@socketio.on('stop')
def handle_stop():
    global stream, is_running, is_recording
    if not is_running:
        return
    is_recording = False
    is_running = False
    if stream:
        try:
            stream.stop(); stream.close()
        except Exception:
            pass
        stream = None
        log_msg("Live stream stopped.")
    else:
        log_msg("Demo stream stopped.")
    socketio.emit('stream_state', {'running': False, 'mode': 'idle'})
    socketio.emit('recording_state', {'recording': False})

@socketio.on('start_recording')
def handle_start_recording():
    global is_recording, recorded_chunks, recording_start_time
    if not is_running:
        log_msg("Start stream first!", "error")
        return
    with recording_lock:
        recorded_chunks = []
    recording_start_time = time_module.time()
    is_recording = True
    log_msg("RECORDING STARTED.", "success")
    socketio.emit('recording_state', {'recording': True})

@socketio.on('stop_recording')
def handle_stop_recording():
    global is_recording
    if not is_recording:
        return
    is_recording = False
    with recording_lock:
        total = sum(c.shape[0] for c in recorded_chunks) if recorded_chunks else 0
    dur = total / SAMPLE_RATE
    log_msg(f"RECORDING STOPPED. {dur:.1f}s ({total} samples)", "success")
    socketio.emit('recording_state', {'recording': False, 'duration': dur})

@app.route('/download_wav')
def download_wav():
    with recording_lock:
        if not recorded_chunks:
            return "No recording data", 404
        all_data = np.concatenate(recorded_chunks, axis=0)
    buf = io.BytesIO()
    with wave.open(buf, 'wb') as wf:
        wf.setnchannels(NUM_GEOPHONES)
        wf.setsampwidth(2)
        wf.setframerate(SAMPLE_RATE)
        int_data = (np.clip(all_data, -1.0, 1.0) * 32767).astype(np.int16)
        wf.writeframes(int_data.tobytes())
    buf.seek(0)
    ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    fname = f"umbrella_seismic_{ts}.wav"
    log_msg(f"WAV download: {fname}", "success")
    return send_file(buf, mimetype='audio/wav', as_attachment=True, download_name=fname)

@app.route('/')
def index():
    return render_template_string(HTML_TEMPLATE)

